A user reports that deleting a todo item does not work -- the item stays in the list. What is wrong?

```jsx
function TodoList() {
  const [todos, setTodos] = useState([
    { id: 1, text: 'Buy milk' },
    { id: 2, text: 'Walk dog' },
  ]);

  function handleDelete(id) {
    const index = todos.findIndex(t => t.id === id);
    todos.splice(index, 1);
    setTodos(todos);
  }

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          {todo.text}
          <button onClick={() => handleDelete(todo.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}
```

You are reviewing AI-generated code for a user profile editor. The client says that changing the city does not work -- it erases the user's name. What would you tell the AI to fix?

```jsx
function ProfileEditor() {
  const [user, setUser] = useState({
    name: 'Alice',
    email: 'alice@example.com',
    address: { city: 'Boston', state: 'MA' }
  });

  function handleCityChange(newCity) {
    setUser({
      address: { city: newCity, state: user.address.state }
    });
  }

  return (
    <div>
      <p>Name: {user.name}</p>
      <p>Email: {user.email}</p>
      <input
        value={user.address.city}
        onChange={(e) => handleCityChange(e.target.value)}
      />
    </div>
  );
}
```
